import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';

interface Project {
  id: number;
  name: string;
  description: string;
  status: 'planning' | 'active' | 'completed' | 'on-hold';
  startDate: string;
  endDate: string;
}

export default function ProjectList() {
  const [projects, setProjects] = useState<Project[]>([]);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const mockProjects: Project[] = [
      { id: 1, name: 'Website Redesign', description: 'Redesign company website', status: 'active', startDate: '2026-01-01', endDate: '2026-06-30' },
      { id: 2, name: 'Mobile App', description: 'Build mobile app', status: 'planning', startDate: '2026-07-01', endDate: '2026-12-31' },
      { id: 3, name: 'API Development', description: 'REST API for backend', status: 'completed', startDate: '2025-01-01', endDate: '2025-06-30' },
    ];
    
    setProjects(mockProjects);
    setLoading(false);
  }, []);

  const filteredProjects = projects.filter(p =>
    p.name.toLowerCase().includes(search.toLowerCase())
  );

  const getStatusColor = (status: string) => {
    const colors: Record<string, string> = {
      active: 'bg-green-100 text-green-800',
      planning: 'bg-blue-100 text-blue-800',
      completed: 'bg-gray-100 text-gray-800',
      'on-hold': 'bg-yellow-100 text-yellow-800',
    };
    return colors[status] || 'bg-gray-100 text-gray-800';
  };

  if (loading) return <div className="p-6">Loading...</div>;

  return (
    <div className="p-6 space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">Projects</h1>
        <Button>New Project</Button>
      </div>

      <Input placeholder="Search projects..." value={search} onChange={(e) => setSearch(e.target.value)} className="max-w-md" />

      <div className="grid gap-4">
        {filteredProjects.map(p => (
          <Link key={p.id} to={`/projects/${p.id}`}>
            <div className="p-4 border rounded-lg hover:shadow-lg transition">
              <div className="flex justify-between items-start mb-2">
                <h3 className="font-semibold text-lg">{p.name}</h3>
                <span className={`px-2 py-1 rounded text-sm font-medium ${getStatusColor(p.status)}`}>
                  {p.status.replace('-', ' ').toUpperCase()}
                </span>
              </div>
              <p className="text-gray-600 mb-2">{p.description}</p>
              <p className="text-sm text-gray-500">
                {new Date(p.startDate).toLocaleDateString()} - {new Date(p.endDate).toLocaleDateString()}
              </p>
            </div>
          </Link>
        ))}
      </div>

      {filteredProjects.length === 0 && (
        <div className="text-center py-8 text-gray-500">No projects found</div>
      )}
    </div>
  );
}
